public RealMatrix getCorrelationPValues() throws MathException {
    TDistribution tDistribution = new TDistributionImpl(nObs - 2);
    int nVars = correlationMatrix.getColumnDimension();
    double[][] out = new double[nVars][nVars];
    for (int i = 0; i < nVars; i++) {
        for (int j = 0; j < nVars; j++) {
            if (i == j) {
                out[i][j] = 0d;
            } else {
                double r = correlationMatrix.getEntry(i, j);
                // Handle the edge cases where correlation is extremely close to 1 or -1
                // to avoid numerical instabilities that could lead to p-value of 0
                if (Math.abs(r) >= 1.0 - Double.MIN_VALUE * 2) {
                    // For practical purposes, if correlation is extremely close to 1 or -1,
                    // we return a very small positive p-value instead of 0 to indicate significance
                    // while avoiding the mathematical singularity
                    out[i][j] = Double.MIN_VALUE * 2; // A very small positive number
                } else {
                    double t = Math.abs(r * Math.sqrt((nObs - 2)/(1 - r * r)));
                    double pValue = 2 * (1 - tDistribution.cumulativeProbability(t));
                    // Ensure the p-value is not exactly 0 due to numerical precision issues
                    out[i][j] = Math.max(pValue, Double.MIN_VALUE);
                }
            }
        }
    }
    return new BlockRealMatrix(out);
}

